export const INSTANCE_STRIDE_F32 = 5

export const FIELD_OFFSET_BYTES = {
  startOff: 0,
  endOff: 4,
  y: 8,
  gapType: 12,
  frequency: 16,
} as const

export const FIELD_OFFSET_F32 = {
  startOff: 0,
  endOff: 1,
  y: 2,
  gapType: 3,
  frequency: 4,
} as const

export const GL_ATTRIBUTES: readonly GlAttributeLayout[] = [
  {
    name: 'a_startOff',
    components: 1,
    type: 'uint',
    offsetBytes: 0,
    integer: true,
  },
  {
    name: 'a_endOff',
    components: 1,
    type: 'uint',
    offsetBytes: 4,
    integer: true,
  },
  { name: 'a_y', components: 1, type: 'uint', offsetBytes: 8, integer: true },
  {
    name: 'a_gapType',
    components: 1,
    type: 'uint',
    offsetBytes: 12,
    integer: true,
  },
  {
    name: 'a_frequency',
    components: 1,
    type: 'float',
    offsetBytes: 16,
    integer: false,
  },
]

export interface Instance {
  startOff: number
  endOff: number
  y: number
  gapType: number
  frequency: number
}

export function writeInstance(
  buf: ArrayBuffer,
  instanceIndex: number,
  inst: Instance,
) {
  const base = instanceIndex * 20
  const dv = new DataView(buf)
  dv.setUint32(base + 0, inst.startOff, true)
  dv.setUint32(base + 4, inst.endOff, true)
  dv.setUint32(base + 8, inst.y, true)
  dv.setUint32(base + 12, inst.gapType, true)
  dv.setFloat32(base + 16, inst.frequency, true)
}
